import java.nio.file.{Files,Paths};object Example extends App{import Brush._;def p(x:Int,y:Int)=Point(x,y);val points=Vector((500,520),(450,450),(390,395),(320,370),(250,370),(180,390),(130,450),(120,520),(155,585),(220,635),(300,650),(380,620),(440,570),(500,520),(560,465),(620,410),(700,370),(770,380),(830,420),(870,480),(875,545),(845,610),(790,660),(720,675),(650,655),(585,610),(540,560),(500,520)).map{case(x,y)=>p(x,y)};assert(buildRoundedDrawingPath(Vector(p(0,0),p(100,0),p(100,100)),40)=="M 0 0 L 55 0 Q 100 0 100 45 L 100 100");val input=args.headOption.getOrElse("assets/example.webp");val output=args.drop(1).headOption.getOrElse("generated/scala.svg");val svg=renderSvg(Files.readAllBytes(Paths.get(input)),"image/webp",1000,1000,points,"🤝 best friends forever",Options(magicGradient=true));Files.createDirectories(Paths.get(output).getParent);Files.writeString(Paths.get(output),svg);println(s"Wrote $output")}
